package orchestrator_test

import (
	"strings"
	"testing"

	"github.com/novshi-tech/boid/internal/orchestrator"
)

// TestCreateTask_RefAutoGenerated verifies that a ref is auto-generated when
// the task has a parent_id but no explicit ref.
func TestCreateTask_RefAutoGenerated(t *testing.T) {
	d := createTestProject(t)

	task := &orchestrator.Task{
		ProjectID: "proj-1",
		Title:     "Child without ref",
		Behavior:  "dev",
		ParentID:  "parent-uuid-auto",
		// Ref intentionally empty
	}
	if err := orchestrator.CreateTask(d.Conn, task); err != nil {
		t.Fatalf("CreateTask: %v", err)
	}
	if task.Ref == "" {
		t.Error("expected Ref to be auto-generated, got empty string")
	}
	// Verify "adjective_noun" format (contains at least one underscore).
	if !strings.Contains(task.Ref, "_") {
		t.Errorf("auto-generated Ref %q does not contain underscore (expected adjective_noun format)", task.Ref)
	}
	// Verify the ref was persisted to the database.
	got, err := orchestrator.GetTask(d.Conn, task.ID)
	if err != nil {
		t.Fatalf("GetTask: %v", err)
	}
	if got.Ref != task.Ref {
		t.Errorf("persisted Ref = %q, want %q", got.Ref, task.Ref)
	}
}

// TestCreateTask_ExplicitRefRespected verifies that an explicitly set ref is used as-is.
func TestCreateTask_ExplicitRefRespected(t *testing.T) {
	d := createTestProject(t)

	task := &orchestrator.Task{
		ProjectID: "proj-1",
		Title:     "Child with explicit ref",
		Behavior:  "dev",
		ParentID:  "parent-uuid-explicit",
		Ref:       "my-step",
	}
	if err := orchestrator.CreateTask(d.Conn, task); err != nil {
		t.Fatalf("CreateTask: %v", err)
	}
	if task.Ref != "my-step" {
		t.Errorf("Ref = %q, want %q", task.Ref, "my-step")
	}
}

// TestCreateTask_ExplicitRefConflict_GetOrCreate verifies that a second create
// with the same (ref, parent_id) returns the existing task (get-or-create),
// not an error. First-write-wins: the original title is preserved.
func TestCreateTask_ExplicitRefConflict_GetOrCreate(t *testing.T) {
	d := createTestProject(t)

	t1 := &orchestrator.Task{
		ProjectID: "proj-1",
		Title:     "First child",
		Behavior:  "dev",
		ParentID:  "parent-conflict",
		Ref:       "shared-ref",
	}
	if err := orchestrator.CreateTask(d.Conn, t1); err != nil {
		t.Fatalf("first CreateTask: %v", err)
	}

	t2 := &orchestrator.Task{
		ProjectID: "proj-1",
		Title:     "Second child (same ref)",
		Behavior:  "dev",
		ParentID:  "parent-conflict",
		Ref:       "shared-ref",
	}
	if err := orchestrator.CreateTask(d.Conn, t2); err != nil {
		t.Fatalf("second CreateTask with same ref: %v (want get-or-create, not error)", err)
	}
	if t2.ID != t1.ID {
		t.Errorf("second CreateTask returned id=%q, want existing id=%q", t2.ID, t1.ID)
	}
	if t2.Title != "First child" {
		t.Errorf("Title = %q, want %q (first-write-wins: original must be preserved)", t2.Title, "First child")
	}
}

// TestCreateTask_AutoRefConflict_Fallback verifies that auto-generated refs avoid
// collisions by picking a different name on conflict.
func TestCreateTask_AutoRefConflict_Fallback(t *testing.T) {
	d := createTestProject(t)
	parentID := "parent-auto-fallback"

	// Create multiple children without refs; each should receive a unique ref.
	const n = 10
	refs := make(map[string]bool, n)
	for i := range n {
		task := &orchestrator.Task{
			ProjectID: "proj-1",
			Title:     "Auto-ref child",
			Behavior:  "dev",
			ParentID:  parentID,
		}
		if err := orchestrator.CreateTask(d.Conn, task); err != nil {
			t.Fatalf("CreateTask[%d]: %v", i, err)
		}
		if task.Ref == "" {
			t.Fatalf("task[%d]: expected auto-generated ref, got empty", i)
		}
		if refs[task.Ref] {
			t.Fatalf("task[%d]: ref %q was already used (collision)", i, task.Ref)
		}
		refs[task.Ref] = true
	}
}

// TestCreateTask_SameRefDifferentParents_OK verifies that the same ref name can
// be used under different parents without conflict.
func TestCreateTask_SameRefDifferentParents_OK(t *testing.T) {
	d := createTestProject(t)

	for i, parentID := range []string{"parent-aaa", "parent-bbb", "parent-ccc"} {
		task := &orchestrator.Task{
			ProjectID: "proj-1",
			Title:     "Same-named step",
			Behavior:  "dev",
			ParentID:  parentID,
			Ref:       "step-1",
		}
		if err := orchestrator.CreateTask(d.Conn, task); err != nil {
			t.Fatalf("CreateTask[%d] (parent=%s): %v", i, parentID, err)
		}
	}
}

// TestCreateTask_NoParent_NoAutoRef verifies that tasks without a parent_id do NOT
// receive an auto-generated ref (refs are parent-scoped).
func TestCreateTask_NoParent_NoAutoRef(t *testing.T) {
	d := createTestProject(t)

	task := &orchestrator.Task{
		ProjectID: "proj-1",
		Title:     "Root task without parent",
		Behavior:  "dev",
		// ParentID and Ref both empty
	}
	if err := orchestrator.CreateTask(d.Conn, task); err != nil {
		t.Fatalf("CreateTask: %v", err)
	}
	if task.Ref != "" {
		t.Errorf("expected Ref to remain empty for root task, got %q", task.Ref)
	}
}

// TestCreateTask_LateChildAutoRef verifies that a child task added after siblings
// also receives a unique auto-generated ref.
func TestCreateTask_LateChildAutoRef(t *testing.T) {
	d := createTestProject(t)
	parentID := "parent-late-child"

	// Create two siblings first.
	sibling1 := &orchestrator.Task{
		ProjectID: "proj-1", Title: "Sibling 1", Behavior: "dev", ParentID: parentID,
	}
	sibling2 := &orchestrator.Task{
		ProjectID: "proj-1", Title: "Sibling 2", Behavior: "dev", ParentID: parentID,
	}
	for _, s := range []*orchestrator.Task{sibling1, sibling2} {
		if err := orchestrator.CreateTask(d.Conn, s); err != nil {
			t.Fatalf("create sibling: %v", err)
		}
	}

	// Now add a late child — it should still get a unique ref.
	late := &orchestrator.Task{
		ProjectID: "proj-1", Title: "Late child", Behavior: "dev", ParentID: parentID,
	}
	if err := orchestrator.CreateTask(d.Conn, late); err != nil {
		t.Fatalf("CreateTask late: %v", err)
	}
	if late.Ref == "" {
		t.Error("late child: expected auto-generated ref, got empty")
	}
	if late.Ref == sibling1.Ref || late.Ref == sibling2.Ref {
		t.Errorf("late child ref %q collides with existing sibling ref", late.Ref)
	}
}
